//go:build llm_generated_opus47

// Package envdoc renders the env-var registry to a Diátaxis-typed
// reference markdown file. Two consumers today:
//
//   - boxer's `env gen-docs` subcommand (cli.go in this package)
//     renders the boxer-side catalogue.
//   - pebble2impl/src/go/cmd/envgen renders the pebble2impl-side
//     catalogue.
//
// Both bind their own side-effect imports of the owner packages whose
// declarations they want to surface; envdoc itself takes no opinion on
// what to load. Render reads env.Snapshot() and formats whatever is
// currently registered.
package envdoc

import (
	"fmt"
	"sort"
	"strings"
	"time"

	"github.com/stergiotis/boxer/public/config/env"
)

// Options customises Render's output.
type Options struct {
	// GeneratorPath is recorded in the YAML front-matter "generator"
	// field and in the leading HTML comment so readers can find the
	// binary that produced the file (e.g. "public/app env gen-docs"
	// for boxer, "src/go/cmd/envgen" for pebble2impl).
	GeneratorPath string

	// RegenerateHint is the literal command shown under the page
	// header (e.g. "go generate ./public/config/env/..."). Empty
	// suppresses the hint paragraph.
	RegenerateHint string

	// Status sets the front-matter `status:` value. Empty defaults to
	// "draft" — machine-generated registry snapshots are pre-human-
	// review by definition (DOCUMENTATION_STANDARD §4), so promoting
	// to "stable" / "accepted" requires an explicit opt-in via this
	// field plus matching ReviewedBy / ReviewedDate (DL003).
	Status string

	// ReviewedBy / ReviewedDate populate the matching front-matter
	// fields (DL003); only honoured when Status is "stable" /
	// "accepted". Empty values are omitted.
	ReviewedBy   string
	ReviewedDate string
}

// Render reads env.Snapshot() and returns the full markdown body.
func Render(opts Options) (out string) {
	specs := env.Snapshot()
	return renderSpecs(specs, opts)
}

func renderSpecs(specs []env.Spec, opts Options) (out string) {
	byCat := map[env.CategoryE][]env.Spec{}
	var cats []env.CategoryE
	seen := map[env.CategoryE]bool{}
	for _, s := range specs {
		if !seen[s.Category] {
			seen[s.Category] = true
			cats = append(cats, s.Category)
		}
		byCat[s.Category] = append(byCat[s.Category], s)
	}
	sort.Slice(cats, func(i, j int) bool {
		return string(cats[i]) < string(cats[j])
	})

	status := opts.Status
	if status == "" {
		// Machine-generated registry snapshots are pre-human-review by
		// definition; default to "draft" so DL003 doesn't fire on
		// stable-without-reviewed-by — matches the rest of the
		// auto-generated skill assets (doc/skills/*/assets/) per
		// DOCUMENTATION_STANDARD §4.
		status = "draft"
	}

	var b strings.Builder
	b.WriteString("---\n")
	b.WriteString("type: reference\n")
	b.WriteString("audience: contributor\n")
	fmt.Fprintf(&b, "status: %s\n", status)
	b.WriteString("generated: true\n")
	if opts.GeneratorPath != "" {
		fmt.Fprintf(&b, "generator: %s\n", opts.GeneratorPath)
	}
	fmt.Fprintf(&b, "generated-at: %s\n", time.Now().UTC().Format(time.RFC3339))
	// Review metadata: only emitted for stable / accepted statuses (DL003
	// requires both for non-draft statuses). Draft outputs leave them
	// off so the snapshot stays self-consistent with the draft banner.
	if status == "stable" || status == "accepted" {
		if opts.ReviewedBy != "" {
			fmt.Fprintf(&b, "reviewed-by: %s\n", opts.ReviewedBy)
		}
		if opts.ReviewedDate != "" {
			fmt.Fprintf(&b, "reviewed-date: %s\n", opts.ReviewedDate)
		}
	}
	b.WriteString("---\n\n")

	// Matching draft banner (DL004) when status is draft. Mirrors the
	// canonical phrasing used by hand-authored doc/ files; the second
	// line provides context specific to machine-generated registries.
	if status == "draft" {
		b.WriteString("> **Status: draft — pre-human-review.** Machine-generated registry snapshot;\n")
		b.WriteString("> regenerated on every IDL or env.Spec change. Do not promote to stable\n")
		b.WriteString("> without freezing the registry contents and adding reviewed-by /\n")
		b.WriteString("> reviewed-date metadata.\n\n")
	}

	b.WriteString("# Environment variables\n\n")
	if opts.GeneratorPath != "" {
		fmt.Fprintf(&b, "<!-- Generated by %s. Do not edit by hand. -->\n\n", opts.GeneratorPath)
	} else {
		b.WriteString("<!-- Generated. Do not edit by hand. -->\n\n")
	}
	intro := fmt.Sprintf("%d variables across %d categories, declared per ADR-0009.",
		len(specs), len(cats))
	if opts.RegenerateHint != "" {
		intro += " Re-run `" + opts.RegenerateHint + "` after adding or modifying specs."
	}
	b.WriteString(intro + "\n\n")

	for _, c := range cats {
		list := byCat[c]
		sort.Slice(list, func(i, j int) bool {
			return list[i].Name < list[j].Name
		})
		fmt.Fprintf(&b, "## %s (%d)\n\n", c, len(list))
		b.WriteString("| Name | Type | Default | CLI flag | Sensitive | Description |\n")
		b.WriteString("|------|------|---------|----------|-----------|-------------|\n")
		for _, s := range list {
			b.WriteString(formatRow(s))
		}
		b.WriteString("\n")
	}

	b.WriteString("## Origins\n\n")
	b.WriteString("| Name | Module | Package |\n")
	b.WriteString("|------|--------|---------|\n")
	for _, s := range specs {
		fmt.Fprintf(&b, "| `%s` | `%s` | `%s` |\n",
			s.Name, s.Origin.Module, s.Origin.Package)
	}

	out = b.String()
	return
}

func formatRow(s env.Spec) (row string) {
	name := fmt.Sprintf("`%s`", s.Name)
	typ := string(s.Type)
	if typ == "" {
		typ = "—"
	}
	def := "—"
	if s.Default != "" {
		def = fmt.Sprintf("`%s`", s.Default)
	}
	flagName := "—"
	if s.CliFlagName != "" {
		flagName = fmt.Sprintf("`--%s`", s.CliFlagName)
	}
	sens := ""
	if s.Sensitive {
		sens = "yes"
	}
	desc := strings.ReplaceAll(s.Description, "|", `\|`)
	desc = strings.ReplaceAll(desc, "\n", " ")
	if len(s.Allowed) > 0 {
		quoted := make([]string, len(s.Allowed))
		for i, v := range s.Allowed {
			quoted[i] = "`" + v + "`"
		}
		desc += "<br>**Allowed:** " + strings.Join(quoted, ` \| `)
	}
	row = fmt.Sprintf("| %s | %s | %s | %s | %s | %s |\n",
		name, typ, def, flagName, sens, desc)
	return
}
